#include <stdio.h>
#include <stdlib.h>
#include <string.h>

static int gcd_int(int a, int b) {
    while (b) { int t = a % b; a = b; b = t; }
    return a;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        int *ans = (int*)calloc(N+1, sizeof(int)); // 1‑based
        // vectors for current pairs (gcd, start)
        int *gcds = (int*)malloc((N+5)*sizeof(int));
        int *starts = (int*)malloc((N+5)*sizeof(int));
        int sz = 0;
        for(int i=0;i<N;i++){
            int new_sz = 0;
            // start with the element itself
            gcds[new_sz] = A[i];
            starts[new_sz] = i;
            new_sz++;
            for(int j=0;j<sz;j++){
                int ng = gcd_int(gcds[j], A[i]);
                if(ng == gcds[new_sz-1]){
                    if(starts[j] < starts[new_sz-1]) starts[new_sz-1] = starts[j];
                }else{
                    gcds[new_sz] = ng;
                    starts[new_sz] = starts[j];
                    new_sz++;
                }
            }
            // update answers
            for(int j=0;j<new_sz;j++){
                int len = i - starts[j] + 1;
                if(gcds[j] > ans[len]) ans[len] = gcds[j];
            }
            // swap buffers
            sz = new_sz;
        }
        // output
        for(int k=1;k<=N;k++){
            if(k>1) printf(" ");
            printf("%d", ans[k]);
        }
        printf("\n");
        free(A); free(ans); free(gcds); free(starts);
    }
    return 0;
}

