#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> A(N);
        for(int &x: A) cin>>x;
        vector<int> ans(N+1,0);
        vector<pair<int,int>> cur; // (gcd, start)
        for(int i=0;i<N;i++){
            vector<pair<int,int>> nxt;
            nxt.emplace_back(A[i], i);
            for(auto &p: cur){
                int ng = std::gcd(p.first, A[i]);
                if(ng == nxt.back().first){
                    nxt.back().second = min(nxt.back().second, p.second);
                }else{
                    nxt.emplace_back(ng, p.second);
                }
            }
            for(auto &p: nxt){
                int len = i - p.second + 1;
                ans[len] = max(ans[len], p.first);
            }
            cur.swap(nxt);
        }
        for(int k=1;k<=N;k++){
            if(k>1) cout<<' ';
            cout<<ans[k];
        }
        cout<<'\n';
    }
    return 0;
}

