import java.io.*;
import java.util.*;

public class Main {
    private static int gcd(int a, int b) {
        while (b != 0) {
            int t = a % b;
            a = b;
            b = t;
        }
        return a;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] A = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) A[i] = Integer.parseInt(st.nextToken());
            int[] ans = new int[N + 1];
            List<int[]> cur = new ArrayList<>(); // each element: [gcd, start]
            for (int i = 0; i < N; i++) {
                List<int[]> nxt = new ArrayList<>();
                nxt.add(new int[]{A[i], i});
                for (int[] p : cur) {
                    int ng = gcd(p[0], A[i]);
                    int[] last = nxt.get(nxt.size() - 1);
                    if (ng == last[0]) {
                        last[1] = Math.min(last[1], p[1]);
                    } else {
                        nxt.add(new int[]{ng, p[1]});
                    }
                }
                for (int[] p : nxt) {
                    int len = i - p[1] + 1;
                    if (p[0] > ans[len]) ans[len] = p[0];
                }
                cur = nxt;
            }
            for (int k = 1; k <= N; k++) {
                if (k > 1) out.append(' ');
                out.append(ans[k]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

