#!/usr/bin/env python3
import sys, math

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        A = [next(it) for _ in range(N)]
        ans = [0] * (N + 1)
        cur = []  # list of (gcd, start)
        for i, val in enumerate(A):
            nxt = [(val, i)]
            for g, s in cur:
                ng = math.gcd(g, val)
                if ng == nxt[-1][0]:
                    # keep earlier start
                    if s < nxt[-1][1]:
                        nxt[-1] = (ng, s)
                else:
                    nxt.append((ng, s))
            for g, s in nxt:
                length = i - s + 1
                if g > ans[length]:
                    ans[length] = g
            cur = nxt
        out_lines.append(' '.join(str(ans[k]) for k in range(1, N + 1)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

