const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let output = [];
function gcd(a, b) {
  while (b !== 0) {
    const t = a % b;
    a = b;
    b = t;
  }
  return a;
}
for (let tc = 0; tc < T; tc++) {
  const N = input[idx++];
  const A = input.slice(idx, idx + N);
  idx += N;
  const ans = new Array(N + 1).fill(0);
  let cur = []; // array of [gcd, start]
  for (let i = 0; i < N; i++) {
    const val = A[i];
    const nxt = [[val, i]];
    for (const [g, s] of cur) {
      const ng = gcd(g, val);
      const last = nxt[nxt.length - 1];
      if (ng === last[0]) {
        if (s < last[1]) last[1] = s;
      } else {
        nxt.push([ng, s]);
      }
    }
    for (const [g, s] of nxt) {
      const len = i - s + 1;
      if (g > ans[len]) ans[len] = g;
    }
    cur = nxt;
  }
  const line = [];
  for (let k = 1; k <= N; k++) line.push(String(ans[k]));
  output.push(line.join(' '));
}
